import { Helmet } from 'react-helmet';
import Header from './components/layout/Header';
import Hero from './components/hero/Hero';
import LeadForm from './components/form/LeadForm';
import Benefits from './components/sections/Benefits';
import Features from './components/sections/Features';
import Pricing from './components/sections/Pricing';
import Steps from './components/sections/Steps';
import FAQ from './components/sections/FAQ';
import FinalCTA from './components/sections/FinalCTA';
import Footer from './components/layout/Footer';

export default function App() {
  return (
    <>
      <Helmet>
        <title>SecureTaxi - Assurance Taxi & VTC | Devis Gratuit en Ligne</title>
        <meta name="description" content="Obtenez votre devis d'assurance taxi en ligne immédiatement. Nous assurons les chauffeurs avec malus, résiliation ou jeune permis. Devis gratuit sous 24h." />
        <meta name="keywords" content="assurance taxi, assurance VTC, assurance décennale,RC Pro, devis taxi, assurance chauffeur, malus taxi, résiliation assurance taxi" />
        <meta property="og:title" content="SecureTaxi - Assurance Taxi & VTC | Devis Gratuit" />
        <meta property="og:description" content="Devis d'assurance taxi en ligne immédiat. Tous profils acceptés, même avec malus ou résiliation." />
        <meta property="og:type" content="website" />
        <meta property="og:url" content="https://securetaxi.fr" />
        <meta name="twitter:card" content="summary_large_image" />
        <link rel="canonical" href="https://securetaxi.fr" />
        <html lang="fr" />
      </Helmet>

      <div className="min-h-screen">
        <Header />
        <main>
          <Hero />
          <LeadForm />
          <Benefits />
          <Features />
          <Pricing />
          <Steps />
          <FAQ />
          <FinalCTA />
        </main>
        <Footer />
      </div>
    </>
  );
}
